-- ============================================================================
-- Full-site Legislacao: Ciro Gomes Gov CE - SAPL Fortaleza Lote A
-- Tabela alvo: legislacao_mandato_executivo
-- Fonte oficial: SAPL Camara Municipal de Fortaleza + auditorias PDF/OCR locais
-- Artefato: fonte interna de curadoria
-- Sem escrita em projetos_lei ou historico_politico.
-- Coverage parcial: ciro-gomes-gov-ce-fortaleza-sapl-ampliado-parcial-lote-a-20260506
-- ============================================================================

DO $$
DECLARE
  v_candidato_id uuid;
  v_hp_count integer;
  v_lme_count integer;
BEGIN
  SELECT id INTO v_candidato_id FROM candidatos WHERE slug = 'ciro-gomes-gov-ce';
  IF v_candidato_id IS NULL THEN
    RAISE NOTICE 'ciro-gomes-gov-ce: candidato ausente neste banco local/CI minimo; seed LME SAPL Fortaleza pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO v_hp_count
  FROM historico_politico
  WHERE candidato_id = v_candidato_id
    AND COALESCE(tipo_evento, 'mandato') = 'mandato'
    AND cargo ILIKE '%Prefeito%Fortaleza%'
    AND upper(coalesce(estado, '')) = 'CE'
    AND coalesce(periodo_inicio, 9999) <= 1989
    AND coalesce(periodo_fim, 0) >= 1990;
  IF v_hp_count <> 1 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: esperava 1 mandato Prefeito Fortaleza/CE 1989-1990, encontrei %', v_hp_count;
  END IF;

  SELECT count(*) INTO v_lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id;
  IF v_lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: esperava 0 rows LME antes do lote, encontrei %', v_lme_count;
  END IF;
END $$;

