INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  municipio_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  c.id,
  hp.id,
  'lei_sancionada',
  'municipal',
  'CE',
  'Fortaleza',
  'Lei Ordinária',
  s.numero,
  s.ano,
  s.data_norma,
  s.ementa,
  'CIRO FERREIRA GOMES',
  'titular',
  s.fonte_primaria_url,
  'SAPL - Camara Municipal de Fortaleza',
  s.texto_integral_url,
  'SAPL-FOR:' || s.id_sapl::text,
  s.metadata
FROM seed_rows s
CROSS JOIN candidatos c
JOIN historico_politico hp
  ON hp.candidato_id = c.id
 AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
 AND hp.cargo ILIKE '%Prefeito%Fortaleza%'
 AND upper(coalesce(hp.estado, '')) = 'CE'
 AND coalesce(hp.periodo_inicio, 9999) <= 1989
 AND coalesce(hp.periodo_fim, 0) >= 1990
WHERE c.slug = 'ciro-gomes-gov-ce'
  AND NOT EXISTS (
    SELECT 1 FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = c.id
      AND lme.identificador_fonte = 'SAPL-FOR:' || s.id_sapl::text
  );

DO $$
DECLARE
  v_candidato_id uuid;
  v_total integer;
  v_scope integer;
  v_projetos integer;
BEGIN
  SELECT id INTO v_candidato_id FROM candidatos WHERE slug = 'ciro-gomes-gov-ce';
  IF v_candidato_id IS NULL THEN
    RAISE NOTICE 'ciro-gomes-gov-ce: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO v_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id;

  SELECT count(*) INTO v_scope
  FROM legislacao_mandato_executivo
  WHERE candidato_id = v_candidato_id
    AND metadata->>'coverage_id' = 'ciro-gomes-gov-ce-fortaleza-sapl-ampliado-parcial-lote-a-20260506'
    AND metadata->>'coverage_scope' = 'fortaleza_municipal_sapl_pdf_ocr_signatario_lote_a_20260506'
    AND signatario = 'CIRO FERREIRA GOMES'
    AND autoridade_papel = 'titular';

  SELECT count(*) INTO v_projetos
  FROM projetos_lei
  WHERE candidato_id = v_candidato_id;

  IF v_total <> 103 THEN
    RAISE EXCEPTION 'Pos-condicao ciro-gomes-gov-ce: esperava 103 rows LME totais, encontrei %', v_total;
  END IF;
  IF v_scope <> 103 THEN
    RAISE EXCEPTION 'Pos-condicao ciro-gomes-gov-ce: esperava 103 rows com coverage/signatario/titular, encontrei %', v_scope;
  END IF;
  IF v_projetos <> 95 THEN
    RAISE EXCEPTION 'Pos-condicao ciro-gomes-gov-ce: projetos_lei deveria permanecer 95, encontrei %', v_projetos;
  END IF;
  RAISE NOTICE 'Pos-apply ciro-gomes-gov-ce Fortaleza SAPL Lote A: lme=% coverage=% projetos_lei=%', v_total, v_scope, v_projetos;
END $$;
